mapper.insert:
INSERT INTO class_record (member_id, class_id)
SELECT member_id, #{classId}
FROM member
WHERE member_no = #{memberId}

mapper.select:
SELECT count(*) FROM class_record
WHERE class_id = #{classId}
  AND status <> 2

SELECT member_no AS memberId, member_name AS memberName, gender, class_id AS classId, class_name AS className, record_id AS recordId, join_time AS joinTime, status, rating FROM v_member_course_rating
AND rating >= #{minRating}
AND gender = #{gender}
ORDER BY rating DESC, join_time DESC, record_id DESC LIMIT #{limit}
